/**
 * MAGI Core — Shared ES Module
 * Auth guard, API client, toast, utilities
 */

const TOKEN_KEY = 'magi_token';
const USER_KEY  = 'magi_user';
const LOGIN_URL = '/login/';

// ─── Auth ─────────────────────────────────────────

export function getToken() { return localStorage.getItem(TOKEN_KEY); }
export function getUser() { try { return JSON.parse(localStorage.getItem(USER_KEY)); } catch { return null; } }

function redirectLogin() {
  if (window.location.pathname.startsWith('/login')) return;
  window.location.href = LOGIN_URL;
}

export async function authGuard() {
  const token = getToken();
  if (!token) { redirectLogin(); return false; }
  try {
    const res = await fetch('/api/auth/me', { headers: { Authorization: `Bearer ${token}` } });
    if (!res.ok) { redirectLogin(); return false; }
    return true;
  } catch { return true; /* offline — don't redirect */ }
}

// ─── API Client ───────────────────────────────────

export async function api(path, options = {}) {
  const token = getToken();
  const url = path.startsWith('/') ? path : `/api/${path}`;
  const headers = { ...options.headers };
  if (token) headers.Authorization = `Bearer ${token}`;
  if (options.body && typeof options.body === 'object' && !(options.body instanceof FormData)) {
    headers['Content-Type'] = 'application/json';
    options.body = JSON.stringify(options.body);
  }
  try {
    const res = await fetch(url, { ...options, headers });
    if (res.status === 401) { redirectLogin(); return { data: null, error: 'Unauthorized' }; }
    const ct = res.headers.get('content-type') || '';
    const data = ct.includes('json') ? await res.json() : await res.text();
    if (!res.ok) {
      const msg = typeof data === 'object' ? (data.error || data.message || 'Request failed') : data;
      return { data: null, error: msg };
    }
    return { data, error: null };
  } catch (err) {
    toast(err.message || 'Network error', 'danger');
    return { data: null, error: err.message };
  }
}

// ─── Toast System ─────────────────────────────────

let _tc = null;
function ensureToastContainer() {
  if (_tc && document.body.contains(_tc)) return _tc;
  _tc = document.createElement('div');
  _tc.className = 'toast-container';
  document.body.appendChild(_tc);
  return _tc;
}

const ICONS = { info: 'ℹ️', success: '✅', warning: '⚠️', danger: '❌' };

export function toast(message, type = 'info', duration = 4000) {
  const c = ensureToastContainer();
  const el = document.createElement('div');
  el.className = `toast toast-${type}`;
  el.innerHTML = `<span>${ICONS[type] || ''}</span><span>${escHtml(message)}</span>`;
  c.appendChild(el);
  const t = setTimeout(() => _removeToast(el), duration);
  el.addEventListener('click', () => { clearTimeout(t); _removeToast(el); });
  while (c.children.length > 5) _removeToast(c.children[0]);
}

function _removeToast(el) {
  if (!el.parentNode) return;
  el.classList.add('toast-out');
  el.addEventListener('animationend', () => el.remove(), { once: true });
}

// ─── Utilities ────────────────────────────────────

export function escHtml(str) {
  if (!str) return '';
  const el = document.createElement('span');
  el.textContent = str;
  return el.innerHTML;
}

export function timeAgo(date) {
  if (!date) return '';
  const ts = typeof date === 'number' ? date : new Date(date).getTime();
  const d = Date.now() - ts;
  if (d < 60000) return 'just now';
  if (d < 3600000) return Math.floor(d / 60000) + 'm ago';
  if (d < 86400000) return Math.floor(d / 3600000) + 'h ago';
  if (d < 2592000000) return Math.floor(d / 86400000) + 'd ago';
  return new Date(ts).toLocaleDateString();
}

export function formatNumber(n) {
  if (n == null) return '0';
  if (n >= 1e6) return (n / 1e6).toFixed(1).replace(/\.0$/, '') + 'M';
  if (n >= 1e3) return (n / 1e3).toFixed(1).replace(/\.0$/, '') + 'K';
  return n.toLocaleString();
}

export function debounce(fn, ms = 300) {
  let timer;
  return function (...args) { clearTimeout(timer); timer = setTimeout(() => fn.apply(this, args), ms); };
}

export function timeStr() {
  return new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

// ─── Loading State ────────────────────────────────

export function setLoading(el, loading) {
  if (!el) return;
  if (loading) {
    el.dataset.origText = el.innerHTML;
    el.disabled = true;
    el.innerHTML = '<span class="spinner spinner-sm"></span>';
    el.style.pointerEvents = 'none';
    el.style.opacity = '0.6';
  } else {
    if (el.dataset.origText !== undefined) { el.innerHTML = el.dataset.origText; delete el.dataset.origText; }
    el.disabled = false;
    el.style.pointerEvents = '';
    el.style.opacity = '';
  }
}

// ─── Init Page ────────────────────────────────────

export async function initPage(opts = {}) {
  window.addEventListener('error', e => console.error('[MAGI]', e.message, e.filename, e.lineno));
  window.addEventListener('unhandledrejection', e => console.error('[MAGI] Promise:', e.reason));
  ensureToastContainer();
  if (!opts.skipAuth) await authGuard();
  return { token: getToken(), user: getUser() };
}

