/**
 * MAGI Transitions — Page transition animations + stagger-item observer
 * ES Module: import { initTransitions, navTo } from '/shared/transitions.js';
 */

// Observe stagger-item elements and animate them in on scroll
function observeStaggerItems() {
  const items = document.querySelectorAll('.stagger-item');
  if (!items.length) return;

  const observer = new IntersectionObserver((entries) => {
    entries.forEach((entry, i) => {
      if (entry.isIntersecting) {
        const el = entry.target;
        const delay = (el.dataset.staggerDelay || 0) * 1;
        const baseDelay = Array.from(el.parentElement?.querySelectorAll('.stagger-item') || []).indexOf(el) * 60;
        setTimeout(() => {
          el.classList.add('stagger-visible');
        }, delay + baseDelay);
        observer.unobserve(el);
      }
    });
  }, { threshold: 0.1 });

  items.forEach(item => observer.observe(item));
}

// Page transition: fade out, navigate
export function navTo(url) {
  const main = document.querySelector('.page-main') || document.querySelector('.rt-main') || document.body;
  main.style.transition = 'opacity 0.2s ease, transform 0.2s ease';
  main.style.opacity = '0';
  main.style.transform = 'translateY(6px)';
  setTimeout(() => {
    window.location.href = url;
  }, 200);
}

// Init: inject CSS for stagger items + observe
export function initTransitions() {
  if (!document.getElementById('magi-transition-styles')) {
    const style = document.createElement('style');
    style.id = 'magi-transition-styles';
    style.textContent = `
      .stagger-item {
        opacity: 0;
        transform: translateY(10px);
        transition: opacity 0.4s cubic-bezier(0.22, 1, 0.36, 1),
                    transform 0.4s cubic-bezier(0.22, 1, 0.36, 1);
      }
      .stagger-item.stagger-visible {
        opacity: 1;
        transform: translateY(0);
      }
      .page-main {
        animation: pageIn 0.35s cubic-bezier(0.22, 1, 0.36, 1);
      }
      @keyframes pageIn {
        from { opacity: 0; transform: translateY(8px); }
        to { opacity: 1; transform: translateY(0); }
      }
    `;
    document.head.appendChild(style);
  }

  // Observe on load and after DOM mutations
  observeStaggerItems();

  const observer = new MutationObserver(() => {
    observeStaggerItems();
  });
  observer.observe(document.body, { childList: true, subtree: true });
}

/**
 * MAGI Count-Up Animation
 * ES Module: import { initCountUp } from '/shared/countup.js';
 * 
 * Usage: <span data-countup="1234"></span>
 * Options: data-countup-duration="2000" (ms), data-countup-prefix="$", data-countup-suffix="%"
 */

function animateCountUp(el) {
  const target = parseFloat(el.dataset.countup) || 0;
  const duration = parseInt(el.dataset.countupDuration) || 1500;
  const prefix = el.dataset.countupPrefix || '';
  const suffix = el.dataset.countupSuffix || '';
  const decimals = (el.dataset.countup.includes('.')) ? (el.dataset.countup.split('.')[1] || '').length : 0;

  const startTime = performance.now();
  const startVal = 0;

  function easeOutExpo(t) {
    return t === 1 ? 1 : 1 - Math.pow(2, -10 * t);
  }

  function formatNumber(n) {
    if (decimals > 0) return n.toFixed(decimals);
    if (n >= 1e6) return (n / 1e6).toFixed(1).replace(/\.0$/, '') + 'M';
    if (n >= 1e3) return (n / 1e3).toFixed(1).replace(/\.0$/, '') + 'K';
    return Math.round(n).toLocaleString();
  }

  function update(currentTime) {
    const elapsed = currentTime - startTime;
    const progress = Math.min(elapsed / duration, 1);
    const easedProgress = easeOutExpo(progress);
    const currentVal = startVal + (target - startVal) * easedProgress;

    el.textContent = prefix + formatNumber(currentVal) + suffix;

    if (progress < 1) {
      requestAnimationFrame(update);
    }
  }

  requestAnimationFrame(update);
}

export function initCountUp() {
  const elements = document.querySelectorAll('[data-countup]');
  if (!elements.length) return;

  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        animateCountUp(entry.target);
        observer.unobserve(entry.target);
      }
    });
  }, { threshold: 0.2 });

  elements.forEach(el => {
    el.textContent = '0';
    observer.observe(el);
  });
}

